sp_widget.client_script:
api.controller=function($scope, $location, $rootScope, spModal, $uibModal, spUtil, amb, $timeout, $log, $window) {
  /* widget controller */
  var c = this;
	// used in _switchTaskFormView to switch form 
	var newObjSelected = {};
		// DFCT0011124 - use this to revert when save or update canceled
	var currentObjSelected = {};
	main();
	function main(){
		c.data.new_task_widget=undefined;
		// DFCT0011107 - moved to client for better response times
		c.data.view = c.data.settings.defaultTaskFormView.sn_view;
		_loadFormWidget();
	}

	// DFCT0011107 moved to client for better response times
	function _loadFormWidget(){
		if(c.data.settings.defaultTaskFormView){
			// reset load query each time
			var loadQuery = c.data.query + c.data.settings.defaultTaskFormView.filter;
			// set loadID above when not advanced, then set query if an ID is set so advanced gets last selected quick type
			c.data.selected_id = c.data.settings.defaultTaskFormView.sys_id;
			// DFCT0011124 - use this to revert when save or update canceled
			_getCurrentObjectSelected();

			// DFCT0011124 - if opening a task, then show header
			var omitHeader = c.data.omitHeader;
			var omitHeaderOptions = c.data.omitHeaderOptions;
			if(c.data.sys_id && c.data.sys_id != -1){
				omitHeaderOptions = false;
				omitHeader = false;
			}
			var form_widget_parameters = {
				table: 'x_153465_discovert_route_task_instance',
				sys_id: c.data.sys_id,
				sys_id_required: false,
				// NOTE: load based on getting user last selection
				view: c.data.view,
				omitHeader: omitHeader,
				omitHeaderOptions: omitHeaderOptions,
				query:  loadQuery,
				bifold: c.data.bifold,
				isModal: c.data.isModal,
				baseWidget: "new_tasker_selection",
				shared: {}
			}
			c.data.submitting=true;
			c.data.new_task_widget = undefined;
			c.data.new_task_widget_forms = [];
			spUtil.get('discovertasker-formtab', form_widget_parameters).then(function(response) {
				var new_task_widget_form = {};
				new_task_widget_form.widget = response;
				c.data.new_task_widget_forms.push(new_task_widget_form);
				c.data.new_task_widget = new_task_widget_form.widget;
				c.data.submitting = false;
				c.data.promptChangesStarted = false;
				c.data.redirectToNew = false;
			});			
		}
	}	

	// ServiceNow dirty flag still popping up, need to figure out how to block it
	$scope.$on('$locationChangeStart', function (event, next, current) {
		var loc = $location.search();
		// url change is actually saving data, skip function in this call
		// this method was added to prompt for save on attempting to leave page
		if(loc.id=="discovertasker_newtask"){
			return undefined;
		}
		if(!c.data.submitting && 
			 !c.data.promptChangesStarted && 
			 !c.data.redirectToNew &&
			 next && current && next != current){
			// DFCT0011107 changed to use consistent call
			var isDataDirty = c.data.new_task_widget && c.data.new_task_widget.checkChanges();
			var nextURL = $location.path();
			if(isDataDirty ){
				_promptDiscardChanges(false, nextURL);
			} else {
				$location.url(nextURL);
				return undefined;

			}
			return undefined;
		}
	});	

	$scope.selectType= function(objSelected){
		// used in _switchTaskFormView to switch form 
		newObjSelected = undefined; // clear selected object
		newObjSelected = objSelected;
		// DFCT0011107 changed to use consistent call
		var isDataDirty = c.data.new_task_widget && c.data.new_task_widget.checkChanges();
		// if dirty, or, this is a saved task and changing the view
		// prompt user
		if(isDataDirty || 
			 (c.data.sys_id && c.data.sys_id != -1 && 
			 c.data.view != newObjSelected.sn_view)){
			_promptDiscardChanges(true);
		} else {
			_switchTaskFormView(true);
		}
	}

	// DFCT0011124 - use this to revert when save or update canceled
	function _getCurrentObjectSelected() {
		currentObjSelected = undefined;
		for (var advType in c.data.advancedTaskerTypes) {
			var objAdvType = c.data.advancedTaskerTypes[advType];
			if(c.data.selected_id == objAdvType.sys_id){
				currentObjSelected = objAdvType;
				break;
			}
		}
		if(!currentObjSelected){
			for (var quickType in c.data.taskerTypes) {
				var objQuickType = c.data.taskerTypes[quickType];
				if(c.data.selected_id == objQuickType.sys_id){
					currentObjSelected = objQuickType;
					break;
				}			
			}
		}
	}	

	function _promptDiscardChanges(switchTaskFormView, newURL){
		var title = "";
		if(!c.data.sys_id || c.data.sys_id == -1){
			title = c.data.messages["Tasker - Save as Draft with New Form View"];
		} else {
			title = c.data.messages["Tasker - Update Form View"];
		}
		var modalSelection = {};
		spModal.open({
			title: title,
			widgetInput: {
				sys_id: c.data.sys_id
			},
			backdrop: 'static',
			widget: 'tasker_modal_save_draft_prompt',
			size: 'md',
			shared: modalSelection,
			buttons: [],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(response) {
			// here when a primary button (Save as Draft OR Discard Changes)
			if(modalSelection.saveDraft){
				c.data.newRec = {};

				// if no sys_id, the post back is called below once the sys_id is returned
				// call here if sys_id exists, no need to wait for save to complete
				if(!c.data.sys_id || c.data.sys_id == -1){
					c.data.promptChangesStarted = true;
					// DFCT0011107 changed to use consistent call
					if(c.data.new_task_widget){
						// DFCT0011124 added logic to receive true false back and set submitting flase based on that
						if(!c.data.new_task_widget.saveAsDraft(newObjSelected)){
							c.data.submitting = false;
						}
					}
				} else {
					if(switchTaskFormView){
						_switchTaskFormView(true);
					} 
					// if not switching forms, no need to redirect to new url on save
					// so no need to do anything if save selected when form closed
				}
			}else if(modalSelection.discardChanges){
				// discard changes selected, change the view, but don't save the form changes
				if(switchTaskFormView){
					_switchTaskFormView(false);
				} else {
					$location.path(newURL);
					return;
				}
			}
		}, function() {
			// cancel selected, do not change view
			// reset prompt for changes for next time through
			c.data.promptChangesStarted = false;			
		});
	}

	function _uiActionComplete(event, params) {
		// DFCT0011376
		if(c.data.sys_id != -1){
			// already have a sys_id, just exit this instead of reloading
			return;
		}

		c.data.submitting = false;
		// if this control is saving based on the modal prompt, reset form view
		if(c.data.promptChangesStarted){
			c.data.sys_id = params.rec_sys_id;
			_switchTaskFormView(false);
			c.data.promptChangesStarted=false;
		}
		// if in modal, the modal should close
		if(c.data.isModal){
			$scope.$parent.$parent.$dismiss();
			// DFCT0011055 - dismiss form, do not redirect
			return;
		}

		// enable form
		// if not save as draft, update or cancel, then redirect to new page
		if(params.action){
			if(params.action.action_name != "save_as_draft" &&
				 params.action.action_name != "sysverb_update"){
				$scope.data.sys_id=params.rec_sys_id;
				$scope.data.getURL=true;
				// without this check there were a couple of unexpected errors in the browser
				if($scope.data.settings &&
					 $scope.data.settings.defaultTaskFormView){
					$scope.data.view=$scope.data.settings.defaultTaskFormView.sn_view;
				}
				spUtil.update($scope).then(function(data) {
					var redirectUrlNew = data.portal_url_ref + '?id=' +  data.pageId + '&sys_id=' + data.sys_id + '&table=' + data.pageTable + '&view=' + data.view;
					// prevent dirty message on new task saved
					c.data.redirectToNew = true;
					$location.url(redirectUrlNew);
				});			
			} else{
				c.data.sys_id = params.rec_sys_id;
				// set new object to current if not set
				if(!newObjSelected){
					newObjSelected = $scope.data.settings.defaultTaskFormView;
				}
				_switchTaskFormView(false);
			}
		}
	}

	// unregister all events
	var unregister_ui_action_triggered = $rootScope.$on("sp.form.ui_action.triggered", _submitStarted);
	// DFCT0011107
	var unregister_gform_submit_failed = $rootScope.$on("sp.form.submit.failed", _submitFailed);

	var unregister_ui_action_complete_triggered = $rootScope.$on("sp.form.ui_action.uiActionComplete", _uiActionComplete);
	var unregister_gform_rendered = $rootScope.$on("spModel.gForm.rendered", _formRendered);

	$scope.$on("$destroy", function() {
		unregister_ui_action_triggered();
		unregister_ui_action_complete_triggered();
		unregister_gform_rendered();
	});

	// DFCT0011107
	function _submitStarted(){
		c.data.submitting = true;
	}

	function _submitFailed(){
		// submit failed.  If selected id isn't new id
		// then save was attempted with new object selected
		// need to revert task form data back to currently selected id
		if(c.data.selected_id !=newObjSelected.sys_id){
			// revert to current object
			_getCurrentObjectSelected();
			_setFilterFields(currentObjSelected);
		}
		// DFCT0011107 another update to clear issue
		c.data.submitting = false;
	}

	function _switchTaskFormView(saveChanges){
		var savingUpdate = false;
		c.data.submitting = true;
		// change selected item in HTML before post back so selection is updated quickly
		if(c.data.selected_id != newObjSelected.sys_id){
			c.data.selected_id = newObjSelected.sys_id;
			$scope.data.defaultTaskFormViewUpdated = true;
			// newObjSelected is set in the selectType function
			$scope.data.settings.defaultTaskFormView = undefined; // clear previous object
			$scope.data.settings.defaultTaskFormView = newObjSelected;
			$scope.data.sys_id = c.data.sys_id;
			spUtil.update($scope).then(function() {
				$scope.data.defaultTaskFormViewUpdated = false;
			});
		}
		_getCurrentObjectSelected();

		if(c.data.sys_id && c.data.sys_id != -1){
			var search = $location.search();
			search.sys_id = c.data.sys_id;
			search.view = newObjSelected.sn_view;
			search.spa = 1;
			$location.search(search).replace();
		}

		// DFCT0011107 - 
		if(c.data.view != newObjSelected.sn_view){
			c.data.view = newObjSelected.sn_view;
		}

		// if task exists, update the saved task to switch to a different view
		if(saveChanges && c.data.sys_id && c.data.sys_id != -1){
			// DFCT0011107 changed to use consistent call
			if(c.data.new_task_widget){
				savingUpdate=true;
				// DFCT0011124 added logic to receive true false back and set submitting flase based on that
				if(!c.data.new_task_widget.updateDraft(newObjSelected)){
					c.data.submitting = false;
					return;
				}
			}
		}
		_loadFormWidget();
		if(!savingUpdate){
			c.data.submitting = false;	
		}
	}

	// when the form is loaded, this event will fire from sub form
	function _formRendered(event, params){
		// DFCT0011069 - tasker type was not getting set when form changed, this should reset it any other fields in the fitler
		// wait for form to finish rendering
		_setFilterFields(newObjSelected);
	}

	// DFCT0011069 - tasker type was not getting set when form changed, this should reset it any other fields in the fitler
	function _setFilterFields(objSelected){
		var fieldValues = [];
		var aFields = [];
		var fieldNameValue = [];
		if(objSelected && objSelected.filter){
			aFields = objSelected.filter.split("^");
			aFields.forEach(function(fieldPair){
				if(fieldPair && fieldPair != ""){
					var fieldNameValuePair = {};
					fieldNameValue = fieldPair.split("=");
					fieldNameValuePair.field = fieldNameValue[0];
					fieldNameValuePair.value = fieldNameValue[1];
					fieldValues.push(fieldNameValuePair);				
				}
			});
		}
		// DFCT0011107 changed to use consistent call
		if(c.data.new_task_widget){
			c.data.new_task_widget.setFieldValues(fieldValues);	
		}
	}

	$scope.convertIsModalToString = function(){
		var result = String(c.data.isModal) || 'false';

		return result;
	}

};

sp_widget.css:
#loading-spinner {
  animation: loading 2s infinite linear;
}

@keyframes loading {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(359deg);
  }
}

.dtech-new-task-container {
  display: flex;
  width:100%;
  height:100%
}

.flex-child {
  flex: 1;
  display:flex;
  flex-direction:column;
  /* position relative allowed flex to apply to the panel */
  position: relative;
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
}  

.flex-child:first-child {
  flex: .4;
} 

/* 2.8 | 2022-07-10 | mmcc | DFCT0011031 - Scrolling doesn't work on the "New" task form. "Advanced Task" fields don't display */
.detech-flex-shadow-25 {
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
}  


/* NOTE: below here should be updated to use dtech naming convention
Once upddated to handle list selector with right side pointer, it should 
move into the service portal style sheets and imported
*/

.component-selector {
  /*background: linear-gradient(to right, #F5F7F9 0%, #F5F7F9 90%, #DDD 100%);*/
  background: #F5F7F9;
}

.component-selector-divider {
  width: 100%;
  height: 2px;
  background-color: rgba(221, 221, 221, 1);
}

.component-selector-header{
  color: rgba(117, 117, 117, 1); /*508 AA*/
  width: 100%;
  padding: 14px 20px 14px 20px;
  font-size: 14px;
  font-weight: 400;
  text-transform: uppercase;
}

.ul-selector {
  margin: 0px;
  padding: 0px;
  list-style-type: none;
  color:#757575;
}

.li-flex-row {
  display: flex;
  flex-grow:0;
  width:100%;
  flex-direction:row;
}

.flex-text {
  flex-grow:1;
}

.li-flex-row-child:first-child {
  flex-grow:1;
}

.li-flex-row-left-pointer {
  width: 0px;
  height: 0px;
  border-left: 10px solid transparent;
  border-right: 10px solid  white;
  border-top: 10px solid  transparent;
  border-bottom: 10px solid  transparent;
  margin: 0px auto;
  z-index: 1000;
}

.li-selector {
  padding: 14px 0px 14px 40px;
  width: 100%;
  color: rgba(0, 0, 0, 1);
  font-size: 14px;
  font-weight: 400;
  cursor:pointer;
}

.li-selector:hover{
  background-color: rgba(217, 237, 247, 1);
}

.li-selected{
  background-color: rgba(231, 244, 253, 1);
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// 2.8 | 2022-05-05 | raj  | STRY0119569 - As a Tasker User, I want to be able to select different form views on New Task Form.
//											New widget built to handle creating new tasks based on task type
// 2.8    | 2022-06-21 - raj -  STRY0116257 - System Setting- Options for limiting available views and setting default "Task Form view" for New Task Forms
//											Updates in Server and HTML
// 2.8 | 2022-07-10 | mmcc | DFCT0011031 - Scrolling doesn't work on the "New" task form. "Advanced Task" fields don't display
//											In HTML, added ng-switch when isModal use flex-child CSS; when default use position absolute, flexbox with child flex-column's
//											In CSS, add detech-flex-shadow-25
//											Updates in HTML and CSS
// 2.8 | 2022-06-21 | raj | DFCT0011069 - On the New Task/sub task screens, Tasker Form fields are reverting to parent Tasker Type when a different tasker type is selected for a sub task
//											Updates in Client Controller
// 2.8 | 2022-07-24 | raj | DFCT0011055 - Upon creation of subtask at "Task Tree" view,  view is changed to "Three Column" view (FOR BOTH QUICK AND ADVANCED TASKING)
//											Updates in Client Controller
// 2.8 | 2022-08-04 | raj | DFCT0011107 - User is unable to switch tasker types after "Some fields are missing" warning displays. Tasker Types become unclickable.
//											Updates in Server Script, Client Controller and HTML
// 2.8 | 2022-08-04 | raj | DFCT0011124 - New Task form does not reload to "Task form with Tabs" when user clicks "Save as a Draft" button on the "Delete form modal"
//                      Updates in Client Script
// 2.8 | 2022-08-13 | raj | STRY0126579 - New Task Form page- Switch Form view modal- New title
//                      updates in client script
// 2.8 | 2022-08-13 | raj | STRY0127296 - (STRETCH) New Task Form- Center the Task Form
//											Changes in HTML - changed .dtech-flex-grow-0dot4-shrink-1-basis-0p to a new .dtech-flex-grow-0dot2-shrink-1-basis-0p for new task form to look better
// 2.8   | 2022-08-18 | raj  | DFCT0011195 - "Create New Task" page does NOT  remember the last selection user made on the New Task form
//																				 Changes in Server Script and Client controller
// 2.8 | 2022-08-30 | mmcc | DFCT0011242 - Add Subtask modal does NOT display the UI action buttons. Create Task, Draft Tasks  (Modal are NOT scrolling)
//                                      In HTML, full rewrite using new CSS selectors and a wrapper div to handle isModal
//                                      Changes made in HTML
// 2.8   | 2022-09-28 | raj  | DFCT0011376 - Creating a sub task from "Draft New Task" UI redirects to that sub task without any visual reinforcement
//																			Changes in client controller, if already have a sys_id, don't redirect to child
//
//------------------------------------------------------------------------------------------------------------------------
(function($sp, input, data, options, gs) {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
	var taskerFormPreferences;

	main();
	function main(){
		taskerFormPreferences = new tasker_User_Form_Preferences();
		// if messages not loaded, load messages
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('new_tasker_selection');

		// save form view preference
		if(input){
			if (input.getURL==true){
				var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
				var url_Properties = {};
				// if just getting the URL, then get URL and return
				url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(input.sys_id,input.view);
				data.sys_id = input.sys_id;
				data.pageId = url_Properties.pageId;
				data.pageTable = url_Properties.pageTable;
				data.view = url_Properties.view;
				data.portal_url_ref = url_Properties.portal_url_ref;
				data.isValid = false;
				data.loadingIndicator = true;
				// only call once
				data.getURL = false;
				return;
			}				

			if(input.defaultTaskFormViewUpdated){
				taskWidgetIconsAndMessage.savePreferenceDefaultTaskFormView(input.settings.defaultTaskFormView.sys_id);
				// DFCT0011195 need to post back, but just to save the default update
				return;
			}
			if(input.sys_id){
				data.sys_id = input.sys_id;
			}
		} else {
			data.sys_id = -1;
		}
		// DFCT0011195 post back update 
		data.messages = [];
		data.settings = {};
		data.advancedTaskerTypes = [];
		data.taskerTypes = [];
		// STRY0116257
		data.showAdvancedViews = false;
		data.showQuickViews = false;
		// load messages
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		// load settings
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);

		data.advancedTaskerTypes = taskerFormPreferences.loadFormViews("advanced_view");
		data.taskerTypes = taskerFormPreferences.loadFormViews("quick_view");
		// STRY0116257
		data.showAdvancedViews = data.advancedTaskerTypes.length>0;
		data.showQuickViews = data.taskerTypes.length>0;

		// DFCT0011271
		data.u_servicenow_form_view = (input || {}).u_servicenow_form_view || 
			(options || {}).u_servicenow_form_view;

		// if form view passsed in, override the loaded view in settings
		if(data.u_servicenow_form_view){
			data.settings.defaultTaskFormView = _getParentFormView(data.u_servicenow_form_view);
		}
		// NOTE: currently the default is saved as a name, but should be saved as object
		data.selected_id = data.settings.defaultTaskFormView.sys_id;
		data.view = data.settings.defaultTaskFormView.sn_view;

		data.bifold = (input || {}).bifold || (options || {}).bifold || false;		
		data.isModal = (input || {}).isModal || (options || {}).isModal || false;
		// if the task has been saved, then show the header and icons
		if(data.sys_id != -1){
			data.omit_icons = false;
			data.omitHeader = false;
		} else {
			data.omit_icons = (input || {}).omit_icons || (options || {}).omit_icons || false;
			data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader || false;
		}
		data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions || false;

		data.query  = (input || {}).query || (options || {}).query || "";
		_convertToBool(['isModal', 'omit_icons']);
	}

	// DFCT0011271 find the parent task view
	function _getParentFormView(u_servicenow_form_view) {
		var parentObjSelected;
		for (var advType in data.advancedTaskerTypes) {
			var objAdvType = data.advancedTaskerTypes[advType];
			if(u_servicenow_form_view == objAdvType.sys_id){
				parentObjSelected = objAdvType;
				break;
			}
		}
		if(!parentObjSelected){
			for (var quickType in data.taskerTypes) {
				var objQuickType = data.taskerTypes[quickType];
				if(u_servicenow_form_view == objQuickType.sys_id){
					parentObjSelected = objQuickType;
					break;
				}			
			}
		}
		return parentObjSelected;
	}		

	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}	
})($sp, input, data, options, gs);
